import { ethers } from 'hardhat';
import { encode } from '../test/helpers';

const valsetPayload: string =
  '';
const signatures = [
  'MEUCIQCbgNyDkzEpS3ueoC42QGqAHGoRO1t/sExyGPSz0g51bQIgdZnmN0yoW0JMOcxfBiFcJ2WNRIFGSrYDyNdCcxWfPX4=',
  '',
  'MEUCIQCGE0IMSwTXklu55SNdnGBUaLqgGcPX7AqL5uaXGIpKvgIgDb0NeIc6ZT9WGw4xXc70pIv85pIUFirqu50KatUqgeY=',
  'MEUCIQDUjDBbXFPCDmEy/AGcQsnUFahIYW9eeIuax+pJ5mN6YgIgYe2K8jCobmDZIA2MaDpo0bWcWMfhjSpWRU9zATmzRaE=',
  'MEUCIQDCtJYOsNji3TDymnoIfi6kd/nBqaO2IlYF+F/nPsiKNQIgei4NWwlZ95PGuMIQ4S952aBAkbG96u6JpdhH/dWKcBQ=',
  'MEUCIQDePFUxJQeJQJGx8RT1vy2NjAnPDXb0+bC9m1tb7kk+QQIgNy67YkKSkPaBORnY7Pxk5a2c9llSyO4dPYMv5EmQj0A=',
  '',
  'MEQCIB7sHffhxyu5xnEiUElpSbJ4wSO3Eb9rUc+z1H6oFJZhAiA8wPZSiM3y5862/WtKD32hTufgCmuZxuM3hmDlZ++2tg==',
  '',
  '',
  'MEUCIQDGWWF+M3SWslZjdzzBSvjWoXwzfRg6bjHd0ZYfZjZTZwIgUoMuawRwKBOwdyUsafaoDmhORMdVOUik3oo1I5ITP0I=',
  'MEUCIQDSGNZfFf8UeDy+q1JcO+t3teBlYceEBTBxjMwutUil+QIgASkfdiLIbfbNrFsB0MWQt/iwX564QJ3DBpzTWFz8yaA=',
  '',
  'MEUCIQCfen5eZPUNiZV5eOBjSrUpyMj4ikQjMCo6Y3Tefi9yvAIgcFcXASwjNaedOCmFy/dkiLOd4avUyDWKlVbXodXWAnw=',
  '',
  'MEQCIFPtagxp6KHJm+kbbtupkYmBuOzmDAX4s/I5YcPNYpf8AiB/dcpKhAQ1wX9jwy2FeQiuFjHwcb/rYBMlB5e5rfIwlg==',
  ''
];

async function main() {
  const ethSigs = signatures
    .map(b64sig => {
      const d = Buffer.from(b64sig, 'base64');
      return `0x${d.toString('hex')}`;
    })
    .map(sig => {
      let rawSig = ethers.getBytes(sig);

      // Extract R and S from the serialized signature
      // The serialized format is: 0x30 <length> 0x02 <length-of-R> <R> 0x02 <length-of-S> <S>
      let rStart = 4; // Skip the first 4 bytes (0x30, total length, 0x02, R length)
      let rLength = rawSig[3];

      // skip 0x00
      if (rawSig[4] == 0) {
        rStart += 1;
        rLength -= 1;
      }
      const sStart = rStart + rLength + 2; // Skip R and 0x02
      const sLength = rawSig[rStart + rLength + 1];

      // Copy R and S into proof, padding to 32 bytes each
      const proof: Uint8Array = new Uint8Array(64);
      proof.set(rawSig.slice(rStart, rStart + rLength), 32 - rLength);
      proof.set(rawSig.slice(sStart, sStart + sLength), 64 - sLength);

      return ethers.hexlify(proof);
    });

  const proof = encode(['bytes[]'], [ethSigs]);

  const consortium = await ethers.getContractAt('Consortium', '0xf9c3D4e6C2a8F0a2E6aB7026cA2060b204585447');

  const p = '0x' + Buffer.from(valsetPayload, 'base64').toString('hex');

  console.log(proof);
  return;

  const tx = await consortium.setNextValidatorSet(p, proof);
  console.log(tx);
}

main().catch(error => {
  console.error(error);
  process.exitCode = 1;
});
